from pathlib import Path
Path("output").mkdir(exist_ok=True)

def clean_row(line):
    name, score = line.strip().split(",")
    return {"name": name.strip().title(), "score": int(score)}

records = []
with open("data/students.csv") as file:
    for line in file:
        try:
            records.append(clean_row(line))
        except ValueError:
            continue

with open("output/clean_students.csv", "w") as file:
    for record in records:
        file.write(f"{record['name']},{record['score']}\n")

print(f"Wrote {len(records)} clean records")

